/**
 * "Workspace Data Explorer" AirApp demo (#12) — the canonical example of an
 * AirApp reading its own workspace's data through **busabase-sdk's typed RPC
 * client** (`createBusabaseRpcClient`), rather than the raw
 * `fetch("/__busabase_api__/api/v1/...")` REST that the Deal Pipeline (#9)
 * and Compliance (#10) demos use. Same bridge, same read-only posture — the
 * difference is the transport: a fully-typed oRPC client generated from the
 * cloud contract.
 *
 * Kept in its own file (like `demo-content-kelly-email.ts`) purely because of
 * size: `busabase-sdk` + its `@orpc/client` dep + the whole cloud contract's
 * zod schema graph esbuild-bundle to a ~418KB minified browser script
 * (`DATA_EXPLORER_CLIENT_JS` below). That bundle is produced AT AUTHORING TIME
 * and baked in as a static `client.js` — the demo's `dev` script is just
 * `node server.js` (a plain static file server), exactly like Kelly Email's
 * pre-bundled `lib/server.js`. esbuild is deliberately NOT a dependency of the
 * demo and is NOT run inside Nodepod: esbuild ships a platform-native binary,
 * the same class of thing Nodepod can't load (see demo #6's `@swc/core`
 * "Failed to load native binding"), so bundling has to happen ahead of time.
 *
 * Nodepod engine ONLY: the `/__busabase_api__/` bridge that the SDK client
 * routes through does not exist under the Local Node.js engine (see the engine
 * capability matrix in `apps/busabase/docs/node-types.md` and the
 * `20260716-airapp-engine-capability-split.md` changelog). Under Local
 * Node.js the demo renders a friendly "bridge unavailable" note instead of a
 * blank screen. Like Kelly Email (npm deps + build step) it is NOT part of the
 * fast baseline seed in `packages/busabase-core/src/demo/scenarios/node-types.en.ts`.
 *
 * RPC methods used (typed against the cloud contract):
 *   - `client.nodes.list({})`             → the workspace node tree; flattened
 *                                            and grouped by `node.type` for the
 *                                            left pane (skips the synthetic
 *                                            space-root wrapper, `parentId === null`).
 *   - `client.docs.get({ nodeId })`        → `{ node, storagePrefix, body }`;
 *                                            `body` rendered as the doc content.
 *   - `client.records.listPaged({ baseId, limit })` → `{ records, nextCursor }`;
 *                                            each row's `headCommit.fields`
 *                                            (a slug→value map) becomes a table.
 *                                            `baseId` comes from the base node's
 *                                            `node.baseId`.
 *   - `client.files.get({ nodeId })`       → `{ node, asset }`; asset metadata
 *                                            (name/mime/size/kind), plus a
 *                                            best-effort text preview via the
 *                                            asset `url`.
 *
 * Deployment-path auto-detect: `apps/busabase` (OSS) mounts RPC at
 * `/api/rpc`; `apps/busabase-cloud` mounts the same procedures under
 * `/api/rpc/core`. A single AirApp runs on either, so the client probes
 * `/__busabase_api__/api/rpc/core` first and falls back to
 * `/__busabase_api__/api/rpc` (one real `nodes.list` call each) — no editing
 * needed to move between busabase and busabase-cloud.
 */

import type { AirAppDemoDef } from "./demo-content";

const DATA_EXPLORER_PACKAGE_JSON =
  '{\n  "name": "workspace-data-explorer",\n  "private": true,\n  "version": "0.1.0",\n  "type": "module",\n  "scripts": {\n    "dev": "node server.js"\n  }\n}';

const DATA_EXPLORER_SERVER_JS =
  'import { createServer } from "node:http";\nimport { readFileSync } from "node:fs";\nimport { extname } from "node:path";\n\n// Same five-line static-file server as the Deal Pipeline demo — the SDK RPC\n// calls to Busabase\'s own API happen client-side (inside client.js, a real\n// browser context routed through the /__busabase_api__ bridge), not here.\nconst contentTypes = {\n  ".html": "text/html; charset=utf-8",\n  ".css": "text/css; charset=utf-8",\n  ".js": "text/javascript; charset=utf-8",\n};\n\ncreateServer((req, res) => {\n  const path = req.url === "/" ? "/index.html" : req.url;\n  try {\n    const body = readFileSync("." + path);\n    res.writeHead(200, {\n      "Content-Type": contentTypes[extname(path)] || "application/octet-stream",\n    });\n    res.end(body);\n  } catch {\n    res.writeHead(404, { "Content-Type": "text/plain; charset=utf-8" });\n    res.end("Not found");\n  }\n}).listen(Number(process.env.PORT) || 3000, () => {\n  console.log("Workspace Data Explorer listening on port " + (Number(process.env.PORT) || 3000));\n});\n';

const DATA_EXPLORER_INDEX_HTML =
  '<!doctype html>\n<html lang="en">\n  <head>\n    <meta charset="UTF-8" />\n    <meta name="viewport" content="width=device-width, initial-scale=1.0" />\n    <title>Workspace Data Explorer</title>\n    <link rel="stylesheet" href="style.css" />\n  </head>\n  <body>\n    <header>\n      <span class="badge">AirApp · busabase-sdk RPC</span>\n      <h1>Workspace Data Explorer</h1>\n      <p>Reads this workspace\'s own nodes via <code>busabase-sdk</code>\'s <code>createBusabaseRpcClient</code> (typed RPC transport), through the <code>/__busabase_api__/</code> bridge. Click a node to drill in.</p>\n      <div id="status" class="status">Loading…</div>\n    </header>\n    <main>\n      <aside id="list" class="pane list-pane"></aside>\n      <section id="detail" class="pane detail-pane">\n        <p class="loading">Select a node on the left to see its content.</p>\n      </section>\n    </main>\n    <script type="module" src="client.js"></script>\n  </body>\n</html>\n';

const DATA_EXPLORER_STYLE_CSS =
  ':root { color-scheme: light; }\n\nbody {\n  margin: 0;\n  min-height: 100vh;\n  font-family: system-ui, -apple-system, "Segoe UI", sans-serif;\n  background: #f8fafc;\n  color: #0f172a;\n}\n\nheader {\n  padding: 1.25rem 2rem 1rem;\n  border-bottom: 1px solid #e2e8f0;\n  background: white;\n}\n\nheader .badge {\n  display: inline-block;\n  padding: 0.2rem 0.6rem;\n  border-radius: 999px;\n  background: #ecfeff;\n  color: #0e7490;\n  font-size: 0.7rem;\n  font-weight: 700;\n  letter-spacing: 0.05em;\n  text-transform: uppercase;\n}\n\nheader h1 { margin: 0.5rem 0 0.25rem; font-size: 1.4rem; }\nheader p { margin: 0 0 0.5rem; color: #64748b; font-size: 0.85rem; max-width: 52rem; }\nheader code { background: #f1f5f9; padding: 0.05rem 0.3rem; border-radius: 0.25rem; font-size: 0.8rem; }\n\n.status { font-size: 0.8rem; color: #475569; }\n.status.error { color: #b91c1c; font-weight: 600; }\n\nmain {\n  display: grid;\n  grid-template-columns: minmax(14rem, 20rem) 1fr;\n  gap: 1rem;\n  padding: 1.5rem 2rem;\n  align-items: start;\n}\n\n.pane {\n  background: white;\n  border: 1px solid #e2e8f0;\n  border-radius: 0.75rem;\n  padding: 0.75rem;\n  min-height: 20rem;\n}\n\n.list-pane .group { margin-bottom: 1rem; }\n.list-pane h3 {\n  font-size: 0.72rem;\n  text-transform: uppercase;\n  letter-spacing: 0.05em;\n  color: #64748b;\n  margin: 0.25rem 0.5rem 0.5rem;\n}\n\n.node {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  gap: 0.5rem;\n  width: 100%;\n  text-align: left;\n  border: none;\n  background: transparent;\n  border-radius: 0.5rem;\n  padding: 0.5rem 0.6rem;\n  font-size: 0.85rem;\n  color: #0f172a;\n  cursor: pointer;\n}\n.node:hover { background: #f1f5f9; }\n.node.active { background: #cffafe; }\n.node-name { font-weight: 500; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }\n.node-type { color: #94a3b8; font-size: 0.7rem; text-transform: uppercase; }\n\n.detail-pane h2 { margin: 0.25rem 0 0.75rem; font-size: 1.1rem; }\n.detail-pane .note { color: #64748b; font-size: 0.82rem; margin: 0 0 0.75rem; }\n.detail-pane .loading { color: #94a3b8; font-size: 0.85rem; }\n.detail-pane .error {\n  color: #b91c1c;\n  font-size: 0.85rem;\n  background: #fef2f2;\n  border: 1px solid #fecaca;\n  border-radius: 0.5rem;\n  padding: 0.75rem;\n}\n\n.doc-body {\n  white-space: pre-wrap;\n  word-break: break-word;\n  background: #f8fafc;\n  border: 1px solid #e2e8f0;\n  border-radius: 0.5rem;\n  padding: 0.75rem;\n  font-size: 0.82rem;\n  line-height: 1.5;\n  max-height: 30rem;\n  overflow: auto;\n}\n\ntable.meta { border-collapse: collapse; font-size: 0.85rem; }\ntable.meta th {\n  text-align: left;\n  color: #64748b;\n  font-weight: 600;\n  padding: 0.3rem 1rem 0.3rem 0;\n  vertical-align: top;\n  white-space: nowrap;\n}\ntable.meta td { padding: 0.3rem 0; }\n\n.table-wrap { overflow: auto; max-height: 30rem; border: 1px solid #e2e8f0; border-radius: 0.5rem; }\ntable.records { border-collapse: collapse; font-size: 0.8rem; width: 100%; }\ntable.records th, table.records td {\n  border-bottom: 1px solid #e2e8f0;\n  padding: 0.4rem 0.6rem;\n  text-align: left;\n  white-space: nowrap;\n}\ntable.records th {\n  background: #f8fafc;\n  color: #475569;\n  position: sticky;\n  top: 0;\n  font-weight: 600;\n}\n\n.empty {\n  margin: 0.5rem;\n  padding: 1.5rem;\n  border: 1px dashed #cbd5e1;\n  border-radius: 0.75rem;\n  color: #64748b;\n  font-size: 0.9rem;\n}\n';

const DATA_EXPLORER_RESPONSIVE_CSS =
  "\n@media (max-width: 640px) {\n  header { padding: 1rem; }\n  main { grid-template-columns: minmax(0, 1fr); padding: 1rem; }\n  .pane { min-height: 12rem; }\n}\n";

